/* ===================================
   心性曲线艺术 - 样式文件
   Heart Curve Art - Styles
   =================================== */

/* CSS 变量 - 设计令牌 */
:root {
    /* 颜色系统 */
    --color-primary: #e91e63;
    --color-primary-light: #f48fb1;
    --color-primary-dark: #c2185b;
    --color-secondary: #9c27b0;
    --color-accent: #ff4081;

    /* 背景色 */
    --bg-dark: #0a0a0f;
    --bg-surface: #12121a;
    --bg-surface-light: #1a1a2e;
    --bg-gradient: linear-gradient(135deg, #0a0a0f 0%, #1a1a2e 50%, #16213e 100%);

    /* 文本色 */
    --text-primary: #ffffff;
    --text-secondary: #b8b8d0;
    --text-muted: #6b6b80;

    /* 边框色 */
    --border-color: rgba(255, 255, 255, 0.1);
    --border-glow: rgba(233, 30, 99, 0.3);

    /* 阴影 */
    --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.3);
    --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.4);
    --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.5);
    --shadow-glow: 0 0 20px rgba(233, 30, 99, 0.4);

    /* 圆角 */
    --radius-sm: 4px;
    --radius-md: 8px;
    --radius-lg: 12px;
    --radius-xl: 16px;
    --radius-full: 9999px;

    /* 间距 */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;

    /* 动画 */
    --transition-fast: 150ms ease;
    --transition-base: 220ms ease;
    --transition-slow: 300ms ease;
    --transition-slower: 500ms ease;

    /* 字体 */
    --font-display: 'Playfair Display', 'Noto Serif SC', serif;
    --font-body: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* 重置样式 */
*, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html, body {
    height: 100%;
    overflow: hidden;
}

body {
    font-family: var(--font-body);
    background: var(--bg-gradient);
    color: var(--text-primary);
    line-height: 1.6;
}

/* ===================================
   背景粒子
   =================================== */
#particles-container {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
    overflow: hidden;
}

.particle {
    position: absolute;
    width: 4px;
    height: 4px;
    background: var(--color-primary);
    border-radius: var(--radius-full);
    opacity: 0.3;
    animation: float 15s infinite ease-in-out;
}

@keyframes float {
    0%, 100% {
        transform: translateY(100vh) rotate(0deg);
        opacity: 0;
    }
    10% {
        opacity: 0.5;
    }
    90% {
        opacity: 0.5;
    }
    100% {
        transform: translateY(-100vh) rotate(720deg);
        opacity: 0;
    }
}

/* ===================================
   主容器布局
   =================================== */
.main-container {
    display: flex;
    height: 100vh;
    position: relative;
    z-index: 1;
}

/* ===================================
   控制面板
   =================================== */
.control-panel {
    width: 320px;
    min-width: 320px;
    background: var(--bg-surface);
    border-right: 1px solid var(--border-color);
    padding: var(--space-4);
    display: flex;
    flex-direction: column;
    gap: var(--space-4);
    overflow-y: auto;
    backdrop-filter: blur(10px);
}

.panel-header {
    text-align: center;
    padding: var(--space-3) 0;
    border-bottom: 1px solid var(--border-color);
}

.panel-header h1 {
    font-family: var(--font-display);
    font-size: 2rem;
    font-weight: 700;
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: var(--space-1);
}

.subtitle {
    color: var(--text-muted);
    font-size: 0.875rem;
    letter-spacing: 2px;
    text-transform: uppercase;
}

/* 控制组 */
.controls-section {
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
}

.control-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
}

.control-group label {
    font-size: 0.875rem;
    color: var(--text-secondary);
    font-weight: 500;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.control-group select,
.control-group input[type="range"] {
    width: 100%;
}

.control-group select {
    padding: var(--space-2) var(--space-3);
    background: var(--bg-surface-light);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    color: var(--text-primary);
    font-size: 0.875rem;
    cursor: pointer;
    transition: all var(--transition-base);
}

.control-group select:hover {
    border-color: var(--border-glow);
}

.control-group select:focus {
    outline: none;
    border-color: var(--color-primary);
    box-shadow: 0 0 0 3px rgba(233, 30, 99, 0.2);
}

/* 滑块样式 */
input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    height: 6px;
    background: var(--bg-surface-light);
    border-radius: var(--radius-full);
    cursor: pointer;
}

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 18px;
    height: 18px;
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    border-radius: var(--radius-full);
    cursor: pointer;
    transition: transform var(--transition-fast);
    box-shadow: var(--shadow-sm);
}

input[type="range"]::-webkit-slider-thumb:hover {
    transform: scale(1.2);
}

input[type="range"]::-moz-range-thumb {
    width: 18px;
    height: 18px;
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    border-radius: var(--radius-full);
    cursor: pointer;
    border: none;
    box-shadow: var(--shadow-sm);
}

.control-group span {
    font-size: 0.75rem;
    color: var(--text-muted);
    text-align: right;
}

/* 按钮组 */
.button-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
    padding: var(--space-3) 0;
    border-top: 1px solid var(--border-color);
    border-bottom: 1px solid var(--border-color);
}

.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: var(--space-2);
    padding: var(--space-3) var(--space-4);
    border: none;
    border-radius: var(--radius-lg);
    font-size: 0.9375rem;
    font-weight: 600;
    cursor: pointer;
    transition: all var(--transition-base);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.btn-icon {
    font-size: 1.125rem;
}

.btn-primary {
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    color: white;
    box-shadow: var(--shadow-glow);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(233, 30, 99, 0.5);
}

.btn-primary:active {
    transform: translateY(0);
}

.btn-secondary {
    background: var(--bg-surface-light);
    color: var(--text-secondary);
    border: 1px solid var(--border-color);
}

.btn-secondary:hover {
    background: var(--bg-gradient);
    color: var(--text-primary);
    border-color: var(--border-glow);
}

.btn-accent {
    background: linear-gradient(135deg, var(--color-secondary), #ba68c8);
    color: white;
}

.btn-accent:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(156, 39, 176, 0.5);
}

/* 信息区域 */
.info-section {
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
    padding: var(--space-3);
    background: var(--bg-surface-light);
    border-radius: var(--radius-lg);
    border: 1px solid var(--border-color);
}

.info-section h3 {
    font-size: 0.875rem;
    color: var(--text-secondary);
    margin-bottom: var(--space-2);
}

.formula {
    font-family: 'Courier New', monospace;
    font-size: 0.8125rem;
    color: var(--color-primary-light);
    line-height: 1.8;
    padding: var(--space-2);
    background: var(--bg-dark);
    border-radius: var(--radius-md);
    border-left: 3px solid var(--color-primary);
}

.stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-2);
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: var(--space-2);
    background: var(--bg-dark);
    border-radius: var(--radius-md);
}

.stat-label {
    font-size: 0.6875rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--color-accent);
}

/* ===================================
   画布区域
   =================================== */
.canvas-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    position: relative;
    overflow: hidden;
}

.canvas-wrapper {
    flex: 1;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    background: radial-gradient(ellipse at center, var(--bg-surface-light) 0%, var(--bg-dark) 100%);
    overflow: hidden;
}

#mainCanvas,
#particleCanvas {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
}

#particleCanvas {
    pointer-events: none;
}

/* 浮动爱心装饰 */
.floating-hearts {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    overflow: hidden;
}

.floating-heart {
    position: absolute;
    font-size: 1.5rem;
    opacity: 0.6;
    animation: floatHeart 8s infinite ease-in-out;
}

@keyframes floatHeart {
    0%, 100% {
        transform: translateY(0) rotate(0deg) scale(1);
        opacity: 0.6;
    }
    25% {
        transform: translateY(-30px) rotate(10deg) scale(1.1);
        opacity: 0.8;
    }
    50% {
        transform: translateY(-20px) rotate(-10deg) scale(0.9);
        opacity: 0.5;
    }
    75% {
        transform: translateY(-40px) rotate(5deg) scale(1.05);
        opacity: 0.7;
    }
}

/* 中心文字 */
.center-text {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
    z-index: 10;
    transition: opacity var(--transition-slow);
}

.center-text.hidden {
    opacity: 0;
    pointer-events: none;
}

.center-text p {
    font-size: 1.25rem;
    color: var(--text-secondary);
    margin-bottom: var(--space-2);
}

.center-text .hint {
    font-size: 0.875rem;
    color: var(--text-muted);
}

/* 底部信息栏 */
.info-bar {
    display: flex;
    justify-content: center;
    gap: var(--space-6);
    padding: var(--space-3) var(--space-4);
    background: var(--bg-surface);
    border-top: 1px solid var(--border-color);
}

.info-item {
    display: flex;
    align-items: center;
    gap: var(--space-2);
    font-size: 0.875rem;
    color: var(--text-secondary);
}

.info-icon {
    font-size: 1.125rem;
}

/* ===================================
   模态框
   =================================== */
.modal {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.8);
    backdrop-filter: blur(5px);
    z-index: 1000;
    align-items: center;
    justify-content: center;
}

.modal.active {
    display: flex;
}

.modal-content {
    background: var(--bg-surface);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-xl);
    max-width: 500px;
    width: 90%;
    max-height: 80vh;
    overflow: auto;
    box-shadow: var(--shadow-lg);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--space-4);
    border-bottom: 1px solid var(--border-color);
}

.modal-header h2 {
    font-family: var(--font-display);
    font-size: 1.5rem;
    color: var(--text-primary);
}

.modal-close {
    background: none;
    border: none;
    color: var(--text-secondary);
    font-size: 1.5rem;
    cursor: pointer;
    transition: color var(--transition-fast);
}

.modal-close:hover {
    color: var(--color-primary);
}

.modal-body {
    padding: var(--space-4);
}

.modal-body p {
    color: var(--text-secondary);
    margin-bottom: var(--space-3);
}

.preview-container {
    background: var(--bg-dark);
    border-radius: var(--radius-lg);
    padding: var(--space-3);
    text-align: center;
}

.preview-container img {
    max-width: 100%;
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-md);
}

/* ===================================
   加载动画
   =================================== */
.loader {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.9);
    z-index: 2000;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: var(--space-4);
}

.loader.active {
    display: flex;
}

.loader-heart {
    width: 50px;
    height: 50px;
    background: var(--color-primary);
    transform: rotate(45deg);
    animation: heartbeat 1.2s infinite;
    box-shadow: var(--shadow-glow);
}

.loader-heart::before,
.loader-heart::after {
    content: '';
    position: absolute;
    width: 50px;
    height: 50px;
    background: var(--color-primary);
    border-radius: var(--radius-full);
}

.loader-heart::before {
    left: -25px;
}

.loader-heart::after {
    top: -25px;
}

@keyframes heartbeat {
    0%, 100% {
        transform: rotate(45deg) scale(1);
    }
    10%, 30% {
        transform: rotate(45deg) scale(0.9);
    }
    20%, 40%, 50%, 60%, 70%, 80% {
        transform: rotate(45deg) scale(1.1);
    }
}

.loader p {
    color: var(--text-secondary);
    font-size: 1.125rem;
    letter-spacing: 2px;
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}

/* ===================================
   响应式设计
   =================================== */
@media (max-width: 768px) {
    .main-container {
        flex-direction: column;
    }

    .control-panel {
        width: 100%;
        min-width: auto;
        max-height: 40vh;
        border-right: none;
        border-bottom: 1px solid var(--border-color);
    }

    .info-bar {
        flex-wrap: wrap;
        gap: var(--space-3);
    }

    .info-item {
        font-size: 0.75rem;
    }
}

/* ===================================
   滚动条样式
   =================================== */
::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: var(--bg-dark);
}

::-webkit-scrollbar-thumb {
    background: var(--border-color);
    border-radius: var(--radius-full);
}

::-webkit-scrollbar-thumb:hover {
    background: var(--border-glow);
}

/* ===================================
   动画类
   =================================== */
.fade-in {
    animation: fadeIn 0.5s ease forwards;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.glow {
    animation: glow 2s ease-in-out infinite;
}

@keyframes glow {
    0%, 100% {
        filter: drop-shadow(0 0 5px var(--color-primary));
    }
    50% {
        filter: drop-shadow(0 0 20px var(--color-primary)) drop-shadow(0 0 30px var(--color-accent));
    }
}

