    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    border-radius: var(--radius-full);
    cursor: pointer;
    transition: transform var(--transition-fast);
    box-shadow: var(--shadow-sm);
}

input[type="range"]::-webkit-slider-thumb:hover {
    transform: scale(1.2);
}

input[type="range"]::-moz-range-thumb {
    width: 18px;
    height: 18px;
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    border-radius: var(--radius-full);
    cursor: pointer;
    border: none;
    box-shadow: var(--shadow-sm);
}

.control-group span {
    font-size: 0.75rem;
    color: var(--text-muted);
    text-align: right;
}

/* 按钮组 */
.button-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
    padding: var(--space-3) 0;
    border-top: 1px solid var(--border-color);
    border-bottom: 1px solid var(--border-color);
}

.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: var(--space-2);
    padding: var(--space-3) var(--space-4);
    border: none;
    border-radius: var(--radius-lg);
    font-size: 0.9375rem;
    font-weight: 600;
    cursor: pointer;
    transition: all var(--transition-base);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.btn-icon {
    font-size: 1.125rem;
}

.btn-primary {
    background: linear-gradient(135deg, var(--color-primary), var(--color-accent));
    color: white;
    box-shadow: var(--shadow-glow);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(233, 30, 99, 0.5);
}

.btn-primary:active {
    transform: translateY(0);
}

.btn-secondary {
    background: var(--bg-surface-light);
    color: var(--text-secondary);
    border: 1px solid var(--border-color);
}

.btn-secondary:hover {
    background: var(--bg-gradient);
    color: var(--text-primary);
    border-color: var(--border-glow);
}

.btn-accent {
    background: linear-gradient(135deg, var(--color-secondary), #ba68c8);
    color: white;
}

.btn-accent:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 24px rgba(156, 39, 176, 0.5);
}

/* 信息区域 */
.info-section {
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
    padding: var(--space-3);
    background: var(--bg-surface-light);
    border-radius: var(--radius-lg);
    border: 1px solid var(--border-color);
}

.info-section h3 {
    font-size: 0.875rem;
    color: var(--text-secondary);
    margin-bottom: var(--space-2);
}

.formula {
    font-family: 'Courier New', monospace;
    font-size: 0.8125rem;
    color: var(--color-primary-light);
    line-height: 1.8;
    padding: var(--space-2);
    background: var(--bg-dark);
    border-radius: var(--radius-md);
    border-left: 3px solid var(--color-primary);
}

.stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-2);
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: var(--space-2);
    background: var(--bg-dark);
    border-radius: var(--radius-md);
}

.stat-label {
    font-size: 0.6875rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--color-accent);
}

/* ===================================
   画布区域
   =================================== */
.canvas-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    position: relative;
    overflow: hidden;
}

.canvas-wrapper {
    flex: 1;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    background: radial-gradient(ellipse at center, var(--bg-surface-light) 0%, var(--bg-dark) 100%);
    overflow: hidden;
}

#mainCanvas,
#particleCanvas {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
}

#particleCanvas {
    pointer-events: none;
}

/* 浮动爱心装饰 */
.floating-hearts {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    overflow: hidden;
}

.floating-heart {
    position: absolute;
    font-size: 1.5rem;
    opacity: 0.6;
    animation: floatHeart 8s infinite ease-in-out;
}

@keyframes floatHeart {
    0%, 100% {
        transform: translateY(0) rotate(0deg) scale(1);
        opacity: 0.6;
    }
    25% {
        transform: translateY(-30px) rotate(10deg) scale(1.1);
        opacity: 0.8;
    }
    50% {
        transform: translateY(-20px) rotate(-10deg) scale(0.9);
        opacity: 0.5;
    }
    75% {
        transform: translateY(-40px) rotate(5deg) scale(1.05);
        opacity: 0.7;
    }
}

/* 中心文字 */
.center-text {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
    z-index: 10;
    transition: opacity var(--transition-slow);
}

.center-text.hidden {
    opacity: 0;
    pointer-events: none;
}

.center-text p {
    font-size: 1.25rem;
    color: var(--text-secondary);
    margin-bottom: var(--space-2);
}

.center-text .hint {
    font-size: 0.875rem;
    color: var(--text-muted);
}

/* 底部信息栏 */
.info-bar {
    display: flex;
    justify-content: center;
    gap: var(--space-6);
    padding: var(--space-3) var(--space-4);
    background: var(--bg-surface);
    border-top: 1px solid var(--border-color);
}

.info-item {
    display: flex;
    align-items: center;
    gap: var(--space-2);
    font-size: 0.875rem;
    color: var(--text-secondary);
}

.info-icon {
    font-size: 1.125rem;
}

/* ===================================
   模态框
   =================================== */
.modal {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.8);
    backdrop-filter: blur(5px);
    z-index: 1000;
    align-items: center;
    justify-content: center;
}

.modal.active {
    display: flex;
}

.modal-content {
    background: var(--bg-surface);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-xl);
    max-width: 500px;
    width: 90%;
    max-height: 80vh;
    overflow: auto;
    box-shadow: var(--shadow-lg);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--space-4);
    border-bottom: 1px solid var(--border-color);
}

.modal-header h2 {
    font-family: var(--font-display);
    font-size: 1.5rem;
    color: var(--text-primary);
}

.modal-close {
    background: none;
    border: none;
    color: var(--text-secondary);
    font-size: 1.5rem;
    cursor: pointer;
    transition: color var(--transition-fast);
}

.modal-close:hover {
    color: var(--color-primary);
}

.modal-body {
    padding: var(--space-4);
}

.modal-body p {
    color: var(--text-secondary);
    margin-bottom: var(--space-3);
}

.preview-container {
    background: var(--bg-dark);
    border-radius: var(--radius-lg);
    padding: var(--space-3);
    text-align: center;
}

.preview-container img {
    max-width: 100%;
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-md);
}

/* ===================================
   加载动画
   =================================== */
.loader {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.9);
    z-index: 2000;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: var(--space-4);
}

.loader.active {
    display: flex;
}

.loader-heart {
    width: 50px;
    height: 50px;
    background: var(--color-primary);
    transform: rotate(45deg);
    animation: heartbeat 1.2s infinite;
    box-shadow: var(--shadow-glow);
}

.loader-heart::before,
.loader-heart::after {
    content: '';
    position: absolute;
    width: 50px;
    height: 50px;
    background: var(--color-primary);
    border-radius: var(--radius-full);
}

.loader-heart::before {
    left: -25px;
}

.loader-heart::after {
    top: -25px;
}

@keyframes heartbeat {
    0%, 100% {
        transform: rotate(45deg) scale(1);
    }
    10%, 30% {
        transform: rotate(45deg) scale(0.9);
    }
    20%, 40%, 50%, 60%, 70%, 80% {
        transform: rotate(45deg) scale(1.1);
    }
}

.loader p {
    color: var(--text-secondary);
    font-size: 1.125rem;
    letter-spacing: 2px;
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}

/* ===================================
   响应式设计
   =================================== */
@media (max-width: 768px) {
    .main-container {
        flex-direction: column;
    }

    .control-panel {
        width: 100%;
        min-width: auto;
        max-height: 40vh;
        border-right: none;
        border-bottom: 1px solid var(--border-color);
    }

    .info-bar {
        flex-wrap: wrap;
        gap: var(--space-3);
    }

    .info-item {
        font-size: 0.75rem;
    }
}

/* ===================================
   滚动条样式
   =================================== */
::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: var(--bg-dark);
}

::-webkit-scrollbar-thumb {
    background: var(--border-color);
    border-radius: var(--radius-full);
}

::-webkit-scrollbar-thumb:hover {
    background: var(--border-glow);
}

/* ===================================
   动画类
   =================================== */
.fade-in {
    animation: fadeIn 0.5s ease forwards;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.glow {
    animation: glow 2s ease-in-out infinite;
}

@keyframes glow {
    0%, 100% {
        filter: drop-shadow(0 0 5px var(--color-primary));
    }
    50% {
        filter: drop-shadow(0 0 20px var(--color-primary)) drop-shadow(0 0 30px var(--color-accent));
    }
}

input.content:
/**
 * 心性曲线艺术 - 主脚本文件
 * Heart Curve Art - Main Script
 */

// ===================================
// 配置和状态
// ===================================
const config = {
    curveType: 'heart2d',
    drawSpeed: 50,
    curveSize: 150,
    colorScheme: 'romantic',
    animationType: 'draw',
    particleCount: 50
};

const state = {
    isDrawing: false,
    animationId: null,
    points: [],
    currentTime: 0,
    hue: 0
};

// ===================================
// DOM 元素
// ===================================
const elements = {
    mainCanvas: document.getElementById('mainCanvas'),
    particleCanvas: document.getElementById('particleCanvas'),
    particlesContainer: document.getElementById('particles-container'),
    floatingHearts: document.getElementById('floatingHearts'),
    centerText: document.getElementById('centerText'),
    loader: document.getElementById('loader'),
    screenshotModal: document.getElementById('screenshotModal'),
    previewContainer: document.getElementById('previewContainer'),

    // 控件
    curveType: document.getElementById('curveType'),
    drawSpeed: document.getElementById('drawSpeed'),
    curveSize: document.getElementById('curveSize'),
    colorScheme: document.getElementById('colorScheme'),
    animationType: document.getElementById('animationType'),
    particleCount: document.getElementById('particleCount'),

    // 显示值
    speedValue: document.getElementById('speedValue'),
    sizeValue: document.getElementById('sizeValue'),
    particleValue: document.getElementById('particleValue'),
    pointsCount: document.getElementById('pointsCount'),
    fpsCount: document.getElementById('fpsCount'),
    formulaDisplay: document.getElementById('formulaDisplay'),

    // 按钮
    btnDraw: document.getElementById('btnDraw'),
    btnClear: document.getElementById('btnClear'),
    btnScreenshot: document.getElementById('btnScreenshot'),
    modalClose: document.getElementById('modalClose')
};

// ===================================
// Canvas 设置
// ===================================
const mainCtx = elements.mainCanvas.getContext('2d');
const particleCtx = elements.particleCanvas.getContext('2d');

function resizeCanvas() {
    const wrapper = elements.mainCanvas.parentElement;
    const size = Math.min(wrapper.clientWidth, wrapper.clientHeight) * 0.8;

    elements.mainCanvas.width = size;
    elements.mainCanvas.height = size;
    elements.particleCanvas.width = size;
    elements.particleCanvas.height = size;

    draw();
}

window.addEventListener('resize', resizeCanvas);

// ===================================
// 颜色方案
// ===================================
const colorSchemes = {
    romantic: {
        primary: ['#ff6b8a', '#ff8fa3', '#ffb3c6', '#ffd6e0'],
        gradient: ['#ff1493', '#ff69b4', '#ffb6c1', '#ffc0cb'],
        glow: 'rgba(255, 105, 180, 0.5)'
    },
    sunset: {
        primary: ['#ff6b35', '#f7c59f', '#efa00b', '#d94033'],
        gradient: ['#ff4500', '#ff6347', '#ffa500', '#ffd700'],
        glow: 'rgba(255, 69, 0, 0.5)'
    },
    ocean: {
        primary: ['#0077b6', '#00b4d8', '#90e0ef', '#caf0f8'],
        gradient: ['#001219', '#005f73', '#0a9396', '#94d2bd'],
        glow: 'rgba(0, 180, 216, 0.5)'
    },
    purple: {
        primary: ['#9d4edd', '#c77dff', '#e0aaff', '#f3d9fa'],
        gradient: ['#4a0080', '#8b00d4', '#ba55d3', '#dda0dd'],
        glow: 'rgba(157, 78, 221, 0.5)'
    },
    rainbow: {
        primary: ['#ff0000', '#ff7f00', '#ffff00', '#00ff00', '#0000ff', '#4b0082', '#9400d3'],
        gradient: ['#ff0000', '#ff7f00', '#ffff00', '#00ff00', '#0000ff', '#4b0082', '#9400d3'],
        glow: 'rgba(255, 255, 255, 0.3)',
        rainbow: true
    },
    gold: {
        primary: ['#ffd700', '#ffed4a', '#fff8dc', '#f0e68c'],
        gradient: ['#b8860b', '#daa520', '#ffd700', '#fffacd'],
        glow: 'rgba(255, 215, 0, 0.5)'
    }
};

// ===================================
// 曲线公式
// ===================================
const formulas = {
    heart2d: {
        fn: (t, size) => ({
            x: 16 * Math.pow(Math.sin(t), 3) * size / 16,
            y: -(13 * Math.cos(t) - 5 * Math.cos(2 * t) - 2 * Math.cos(3 * t) - Math.cos(4 * t)) * size / 16
        }),
        formula: 'x = 16sin³(t)<br>y = 13cos(t) - 5cos(2t)<br>- 2cos(3t) - cos(4t)'
    },
    heart3d: {
        fn: (t, size) => ({
            x: size * Math.cos(t) * Math.cos(t) * Math.cos(t),
            y: size * Math.cos(t) * Math.cos(t) * Math.sin(t)
        }),
        formula: 'x = r·cos³(t)·cos(t)<br>y = r·cos³(t)·sin(t)<br>r = 1 + sin(t)'
    },
    cardioid: {
        fn: (t, size) => ({
            x: size * (1 - Math.cos(t)) * Math.cos(t),
            y: size * (1 - Math.cos(t)) * Math.sin(t)
        }),
        formula: 'x = a(1-cos(t))cos(t)<br>y = a(1-cos(t))sin(t)'
    },
    spiral: {
        fn: (t, size) => ({
            x: size * t * Math.cos(t) * Math.sin(t),
            y: size * t * Math.sin(t) * Math.sin(t)
        }),
        formula: 'x = t·cos(t)·sin(t)<br>y = t·sin²(t)'
    },
    double: {
        fn: (t, size) => ({
            x: size * Math.sin(t) * Math.cos(t),
            y: size * Math.sin(t) * Math.sin(t)
        }),
        formula: 'x = a·sin(t)cos(t)<br>y = a·sin²(t)'
    },
    butterfly: {
        fn: (t, size) => ({
            x: size * Math.sin(t) * (Math.exp(Math.cos(t)) - 2 * Math.cos(4 * t) - Math.pow(Math.sin(t / 12), 5)),
            y: size * Math.cos(t) * (Math.exp(Math.cos(t)) - 2 * Math.cos(4 * t) - Math.pow(Math.sin(t / 12), 5))
        }),
        formula: 'x = sin(t)(e^cos(t)-2cos(4t)-sin⁵(t/12))<br>y = cos(t)(e^cos(t)-2cos(4t)-sin⁵(t/12))'
    }
};

// ===================================
// 绘制函数
// ===================================
function getColor(t, totalT, scheme) {
    const colors = colorSchemes[scheme];

    if (colors.rainbow) {
        const hue = (t / totalT) * 360;
        return `hsl(${hue}, 100%, 50%)`;
    }

    const index = Math.floor((t / totalT) * colors.primary.length);
    return colors.primary[Math.min(index, colors.primary.length - 1)];
}

function getGradient(ctx, scheme) {
    const colors = colorSchemes[scheme];
    const gradient = ctx.createLinearGradient(-config.curveSize, -config.curveSize, config.curveSize, config.curveSize);

    colors.gradient.forEach((color, i) => {
        gradient.addColorStop(i / (colors.gradient.length - 1), color);
    });

    return gradient;
}

function draw() {
    if (state.isDrawing) return;

    const ctx = mainCtx;
    const size = config.curveSize;
    const centerX = elements.mainCanvas.width / 2;
    const centerY = elements.mainCanvas.height / 2;

    // 清空画布
    ctx.clearRect(0, 0, elements.mainCanvas.width, elements.mainCanvas.height);

    // 保存状态
    ctx.save();
    ctx.translate(centerX, centerY);

    // 获取曲线公式
    const curve = formulas[config.curveType];

    // 生成点
    const points = [];
    const totalPoints = 1000;

    for (let i = 0; i <= totalPoints; i++) {
        const t = (i / totalPoints) * Math.PI * 2;
        const point = curve.fn(t, size);
        points.push(point);
    }

    // 绘制曲线
    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);

    const gradient = getGradient(ctx, config.colorScheme);
    ctx.strokeStyle = gradient;
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    // 添加发光效果
    ctx.shadowColor = colorSchemes[config.colorScheme].glow;
    ctx.shadowBlur = 20;

    for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y);
    }

    ctx.stroke();

    // 绘制填充（如果适用）
    if (config.curveType === 'heart2d' || config.curveType === 'cardioid') {
        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        for (let i = 1; i < points.length; i++) {
            ctx.lineTo(points[i].x, points[i].y);
        }
        ctx.closePath();

        const fillGradient = ctx.createRadialGradient(0, 0, 0, 0, 0, size * 2);
        const colors = colorSchemes[config.colorScheme].gradient;
        fillGradient.addColorStop(0, colors[0] + '40');
        fillGradient.addColorStop(1, colors[colors.length - 1] + '10');
        ctx.fillStyle = fillGradient;
        ctx.fill();
    }

    // 恢复状态
    ctx.restore();

    // 更新点数显示
    elements.pointsCount.textContent = points.length;
}

// ===================================
// 动画绘制
// ===================================
function animateDraw() {
    const ctx = mainCtx;
    const size = config.curveSize;
    const centerX = elements.mainCanvas.width / 2;
    const centerY = elements.mainCanvas.height / 2;
    const curve = formulas[config.curveType];
    const speed = config.drawSpeed / 50;

    // 清空画布
    ctx.clearRect(0, 0, elements.mainCanvas.width, elements.mainCanvas.height);

    // 保存状态
    ctx.save();
    ctx.translate(centerX, centerY);

    // 添加发光效果
    ctx.shadowColor = colorSchemes[config.colorScheme].glow;
    ctx.shadowBlur = 20;

    // 绘制已有点
    if (state.points.length > 1) {
        ctx.beginPath();
        ctx.moveTo(state.points[0].x, state.points[0].y);

        const gradient = getGradient(ctx, config.colorScheme);
        ctx.strokeStyle = gradient;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';

        for (let i = 1; i < state.points.length; i++) {
            ctx.lineTo(state.points[i].x, state.points[i].y);
        }

        ctx.stroke();
    }

    // 添加新点
    const pointsPerFrame = Math.ceil(speed * 5);
    const totalPoints = 1000;

    for (let i = 0; i < pointsPerFrame && state.currentTime < totalPoints; i++) {
        const t = (state.currentTime / totalPoints) * Math.PI * 2;
        const point = curve.fn(t, size);
        state.points.push(point);
        state.currentTime++;
    }

    // 更新显示
    elements.pointsCount.textContent = state.points.length;

    // 恢复状态
    ctx.restore();

    // 检查是否完成
    if (state.currentTime >= totalPoints) {
        state.isDrawing = false;
        elements.loader.classList.remove('active');
        elements.centerText.classList.add('hidden');
    } else {
        state.animationId = requestAnimationFrame(animateDraw);
    }
}

function startDrawing() {
    if (state.isDrawing) return;

    state.isDrawing = true;
    state.points = [];
    state.currentTime = 0;

    elements.centerText.classList.add('hidden');
    elements.loader.classList.add('active');

    // 更新公式显示
    elements.formulaDisplay.innerHTML = formulas[config.curveType].formula;

    animateDraw();
}

// ===================================
// 粒子效果
// ===================================
function createParticles() {
    const container = elements.particlesContainer;
    container.innerHTML = '';

    for (let i = 0; i < 30; i++) {
        const particle = document.createElement('div');
        particle.className = 'particle';
        particle.style.left = Math.random() * 100 + '%';
        particle.style.animationDelay = Math.random() * 15 + 's';
        particle.style.animationDuration = (10 + Math.random() * 10) + 's';

        const colors = ['#ff6b8a', '#ff8fa3', '#ffb3c6', '#ffd6e0', '#9d4edd', '#c77dff'];
        particle.style.background = colors[Math.floor(Math.random() * colors.length)];

        container.appendChild(particle);
    }
}

function createFloatingHearts() {
    const container = elements.floatingHearts;
    container.innerHTML = '';

    const hearts = ['❤️', '💕', '💗', '💖', '✨', '⭐'];

    for (let i = 0; i < 15; i++) {
        const heart = document.createElement('div');
        heart.className = 'floating-heart';
        heart.textContent = hearts[Math.floor(Math.random() * hearts.length)];
        heart.style.left = Math.random() * 100 + '%';
        heart.style.top = Math.random() * 100 + '%';
        heart.style.animationDelay = Math.random() * 8 + 's';
        heart.style.fontSize = (1 + Math.random() * 1.5) + 'rem';

        container.appendChild(heart);
    }
}

// ===================================
// 脉动动画
// ===================================
let pulseScale = 1;
let pulseDirection = 1;

function animatePulse() {
    if (config.animationType !== 'pulse') return;

    pulseScale += 0.005 * pulseDirection;
    if (pulseScale > 1.1 || pulseScale < 0.9) {
        pulseDirection *= -1;
    }

    mainCtx.save();
    const centerX = elements.mainCanvas.width / 2;
    const centerY = elements.mainCanvas.height / 2;
    mainCtx.translate(centerX, centerY);
    mainCtx.scale(pulseScale, pulseScale);
    mainCtx.translate(-centerX, -centerY);

    draw();
    mainCtx.restore();

    state.animationId = requestAnimationFrame(animatePulse);
}

// ===================================
// 旋转动画
// ===================================
let rotation = 0;

function animateRotate() {
    if (config.animationType !== 'rotate') return;

    rotation += 0.01;

    mainCtx.save();
    const centerX = elements.mainCanvas.width / 2;
    const centerY = elements.mainCanvas.height / 2;
    mainCtx.translate(centerX, centerY);
    mainCtx.rotate(rotation);
    mainCtx.translate(-centerX, -centerY);

    draw();
    mainCtx.restore();

    state.animationId = requestAnimationFrame(animateRotate);
}

// ===================================
// 闪耀效果
// ===================================
function animateSparkle() {
    if (config.animationType !== 'sparkle') return;

    const ctx = particleCtx;
    ctx.clearRect(0, 0, elements.particleCanvas.width, elements.particleCanvas.height);

    const centerX = elements.particleCanvas.width / 2;
    const centerY = elements.particleCanvas.height / 2;
    const size = config.curveSize;

    // 绘制随机闪耀点
    for (let i = 0; i < 20; i++) {
        const t = Math.random() * Math.PI * 2;
        const curve = formulas[config.curveType];
        const point = curve.fn(t, size * 0.9);

        const x = centerX + point.x;
        const y = centerY + point.y;
        const alpha = 0.5 + Math.random() * 0.5;

        ctx.beginPath();
        ctx.arc(x, y, 2 + Math.random() * 3, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        ctx.fill();
    }

    state.animationId = requestAnimationFrame(animateSparkle);
}

// ===================================
// 动画管理
// ===================================
function startAnimation() {
    if (state.animationId) {
        cancelAnimationFrame(state.animationId);
    }

    switch (config.animationType) {
        case 'pulse':
            animatePulse();
            break;
        case 'rotate':
            animateRotate();
            break;
        case 'sparkle':
            animateSparkle();
            break;
        default:
            draw();
    }
}

// ===================================
