    }
});

elements.colorScheme.addEventListener('change', (e) => {
    config.colorScheme = e.target.value;
    if (!state.isDrawing) {
        draw();
        startAnimation();
    }
});

elements.animationType.addEventListener('change', (e) => {
    config.animationType = e.target.value;
    startAnimation();
});

elements.particleCount.addEventListener('input', (e) => {
    config.particleCount = parseInt(e.target.value);
