// ===================================
let lastTime = performance.now();
let frameCount = 0;

function updateFPS() {
    const now = performance.now();
    frameCount++;

    if (now - lastTime >= 1000) {
        elements.fpsCount.textContent = frameCount;
        frameCount = 0;
        lastTime = now;
    }

    requestAnimationFrame(updateFPS);
}

// ===================================
// 初始化
// ===================================
function init() {
    resizeCanvas();
    createParticles();
    createFloatingHearts();
    updateFPS();
    draw();

