    elements.speedValue.textContent = config.drawSpeed + '%';
});

elements.curveSize.addEventListener('input', (e) => {
    config.curveSize = parseInt(e.target.value);
    elements.sizeValue.textContent = config.curveSize;
    if (!state.isDrawing) {
        draw();
    }
});

elements.colorScheme.addEventListener('change', (e) => {
    config.colorScheme = e.target.value;
    if (!state.isDrawing) {
        draw();
        startAnimation();
    }
});

elements.animationType.addEventListener('change', (e) => {
    config.animationType = e.target.value;
    startAnimation();
});

elements.particleCount.addEventListener('input', (e) => {
    config.particleCount = parseInt(e.target.value);
    elements.particleValue.textContent = config.particleCount;
});

elements.btnDraw.addEventListener('click', () => {
    if (state.animationId) {
        cancelAnimationFrame(state.animationId);
    }
    startDrawing();
});

elements.btnClear.addEventListener('click', () => {
    if (state.animationId) {
        cancelAnimationFrame(state.animationId);
    }
    state.isDrawing = false;
    state.points = [];
    state.currentTime = 0;
    mainCtx.clearRect(0, 0, elements.mainCanvas.width, elements.mainCanvas.height);
    particleCtx.clearRect(0, 0, elements.particleCanvas.width, elements.particleCanvas.height);
    elements.centerText.classList.remove('hidden');
    elements.pointsCount.textContent = '0';
});

elements.btnScreenshot.addEventListener('click', takeScreenshot);

elements.modalClose.addEventListener('click', () => {
    elements.screenshotModal.classList.remove('active');
});

elements.screenshotModal.addEventListener('click', (e) => {
    if (e.target === elements.screenshotModal) {
        elements.screenshotModal.classList.remove('active');
    }
});

// ===================================
// 帧率显示
// ===================================
let lastTime = performance.now();
let frameCount = 0;

function updateFPS() {
    const now = performance.now();
    frameCount++;

    if (now - lastTime >= 1000) {
        elements.fpsCount.textContent = frameCount;
        frameCount = 0;
        lastTime = now;
    }

    requestAnimationFrame(updateFPS);
}

// ===================================
// 初始化
// ===================================
function init() {
    resizeCanvas();
    createParticles();
    createFloatingHearts();
    updateFPS();
    draw();

    // 设置初始公式显示
    elements.formulaDisplay.innerHTML = formulas[config.curveType].formula;
}

init();
